1391 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1392 |     function applyLocalPatch(content, ops) {
1393 |         let lines = content.split('\n');
1394 |         let logs = [];
1395 |         let success = true;
1396 | 
1397 |         if (typeof ops === 'string') {
1398 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1399 |         }
1400 | 
1401 |         ops.forEach(op => {
1402 |             if (op.action === 'comment') return;
1403 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1404 |             
1405 |             if (op.action === 'replace_block') {
1406 |                 // Strategy 1: Exact String Match (Fastest)
1407 |                 const currentStr = lines.join('\n');
1408 |                 if (currentStr.includes(op.find_block)) {
1409 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1410 |                     logs.push('Exact match applied');
1411 |                     return;
1412 |                 }
1413 | 
1414 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1415 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1416 |                 if (searchLines.length === 0) return;
1417 | 
1418 |                 let matchStart = -1;
1419 |                 let matchEnd = -1;
1420 | 
1421 |                 // Scan file lines
1422 |                 for (let i = 0; i < lines.length; i++) {
1423 |                     // If first line matches (ignoring whitespace)
1424 |                     if (lines[i].trim() === searchLines[0]) {
1425 |                         // Check subsequent lines
1426 |                         let allMatch = true;
1427 |                         let fileOffset = 0;
1428 |                         let searchOffset = 1;
1429 |                         
1430 |                         while (searchOffset < searchLines.length) {
1431 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1432 |                             const nextFile = lines[i + fileOffset + 1].trim();
1433 |                             // Skip empty lines in file if they aren't in search block
1434 |                             if (nextFile === '') {
1435 |                                 fileOffset++;
1436 |                                 continue;
1437 |                             }
1438 |                             if (nextFile !== searchLines[searchOffset]) {
1439 |                                 allMatch = false;
1440 |                                 break;
1441 |                             }
1442 |                             fileOffset++;
1443 |                             searchOffset++;
1444 |                         }
1445 | 
1446 |                         if (allMatch) {
1447 |                             matchStart = i;
1448 |                             matchEnd = i + fileOffset;
1449 |                             break;
1450 |                         }
1451 |                     }
1452 |                 }
1453 | 
1454 |                 if (matchStart !== -1) {
1455 |                     // Replace the range of lines
1456 |                     const replacement = op.replace_with.split('\n');
1457 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1458 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1459 |                 } else {
1460 |                     success = false;
1461 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1462 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1463 |                 }
1464 |             }
1465 |         });
1466 |         return { content: lines.join('\n'), success, logs };
1467 |     }
