3638 |     function formatBytes(bytes) {
3639 |         if (!bytes) return '0 B';
3640 |         const k = 1024;
3641 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3642 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3643 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3644 |     }
