3646 |     function timeAgo(dateString) {
3647 |         const date = new Date(dateString);
3648 |         const now = new Date();
3649 |         const seconds = Math.floor((now - date) / 1000);
3650 |         if (seconds < 10) return 'just now';
3651 |         if (seconds < 60) return seconds + 's ago';
3652 |         const minutes = Math.floor(seconds / 60);
3653 |         if (minutes < 60) return minutes + 'm ago';
3654 |         const hours = Math.floor(minutes / 60);
3655 |         if (hours < 24) return hours + 'h ago';
3656 |         return date.toLocaleDateString();
3657 |     }
