3795 |                 while (curr && curr !== scrollContainer) {
3796 |                     offsetTop += curr.offsetTop;
3797 |                     curr = curr.offsetParent;
3798 |                 }
3799 | 
3800 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
3801 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
3802 | 
3803 |                 // Visual Highlight
