3811 |                 
3812 |                 console.groupEnd();
3813 |                 return true;
3814 |             }
3815 | 
3816 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
3817 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
3818 |                 retryCount++;
3819 |                 showGlobalToast("🔍 Searching deeper...");
3820 |                 
3821 |                 await loadMoreFn(); 
3822 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
3823 |                 return attemptNavigation();
3824 |             }
3825 | 
3826 |             console.error("[DeepJump] Failed: Element not found after retries.");
3827 |             showGlobalToast("Entry not found in recent history.", true);
3828 |             console.groupEnd();
3829 |             return false;
3830 |         };
