1233 |         stack.pop(); 
1234 |         const parts = relative.split('/');
1235 |         for (let i = 0; i < parts.length; i++) {
1236 |             if (parts[i] === '.') continue;
1237 |             if (parts[i] === '..') stack.pop();
1238 |             else stack.push(parts[i]);
