1390 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1391 |     function applyLocalPatch(content, ops) {
1392 |         let lines = content.split('\n');
1393 |         let logs = [];
1394 |         let success = true;
1395 | 
1396 |         if (typeof ops === 'string') {
1397 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1398 |         }
1399 | 
1400 |         ops.forEach(op => {
1401 |             if (op.action === 'comment') return;
1402 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1403 |             
1404 |             if (op.action === 'replace_block') {
1405 |                 // Strategy 1: Exact String Match (Fastest)
1406 |                 const currentStr = lines.join('\n');
1407 |                 if (currentStr.includes(op.find_block)) {
1408 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1409 |                     logs.push('Exact match applied');
1410 |                     return;
1411 |                 }
1412 | 
1413 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1414 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1415 |                 if (searchLines.length === 0) return;
1416 | 
1417 |                 let matchStart = -1;
1418 |                 let matchEnd = -1;
1419 | 
1420 |                 // Scan file lines
1421 |                 for (let i = 0; i < lines.length; i++) {
1422 |                     // If first line matches (ignoring whitespace)
1423 |                     if (lines[i].trim() === searchLines[0]) {
1424 |                         // Check subsequent lines
1425 |                         let allMatch = true;
1426 |                         let fileOffset = 0;
1427 |                         let searchOffset = 1;
1428 |                         
1429 |                         while (searchOffset < searchLines.length) {
1430 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1431 |                             const nextFile = lines[i + fileOffset + 1].trim();
1432 |                             // Skip empty lines in file if they aren't in search block
1433 |                             if (nextFile === '') {
1434 |                                 fileOffset++;
1435 |                                 continue;
1436 |                             }
1437 |                             if (nextFile !== searchLines[searchOffset]) {
1438 |                                 allMatch = false;
1439 |                                 break;
1440 |                             }
1441 |                             fileOffset++;
1442 |                             searchOffset++;
1443 |                         }
1444 | 
1445 |                         if (allMatch) {
1446 |                             matchStart = i;
1447 |                             matchEnd = i + fileOffset;
1448 |                             break;
1449 |                         }
1450 |                     }
1451 |                 }
1452 | 
1453 |                 if (matchStart !== -1) {
1454 |                     // Replace the range of lines
1455 |                     const replacement = op.replace_with.split('\n');
1456 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1457 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1458 |                 } else {
1459 |                     success = false;
1460 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1461 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1462 |                 }
1463 |             }
1464 |         });
1465 |         return { content: lines.join('\n'), success, logs };
1466 |     }
