1470 |     async function runAutoFixLoop(name, code, errorList) {
1471 |         const status = document.getElementById('ef-status-msg');
1472 |         let currentCode = code;
1473 |         let currentErrors = errorList;
1474 | 
1475 |         // Fix one by one (recursive loop)
1476 |         async function fixNext(index) {
1477 |             if (index >= currentErrors.length) return true; // All initial errors processed
1478 | 
1479 |             const err = currentErrors[index];
1480 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
1481 |             status.style.color = "#eab308"; // Dev yellow
1482 | 
1483 |             try {
1484 |                 // 1. Get Patch from AI
1485 |                 const res = await fetch(CONFIG.funcUrl, { 
1486 |                     method: 'POST', 
1487 |                     headers: {'Content-Type': 'application/json'},
1488 |                     body: apiBody({ 
1489 |                         action: 'propose_syntax_fix', 
1490 |                         code: currentCode, 
1491 |                         error: err 
1492 |                     })
1493 |                 });
1494 |                 const data = await res.json();
1495 |                 const ops = data.operations;
1496 | 
1497 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
1498 | 
1499 |                 // 2. Apply Patch Locally
1500 |                 const patchResult = applyLocalPatch(currentCode, ops);
1501 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
1502 | 
1503 |                 currentCode = patchResult.content;
1504 |                 document.getElementById('ef-code').value = currentCode; // Update UI
1505 | 
1506 |                 // 3. Re-Validate
1507 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
1508 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
1509 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
1510 |                 });
1511 |                 const scanData = await scanRes.json();
1512 | 
1513 |                 if (scanData.valid) {
1514 |                     status.innerText = "✅ Syntax Fixed!";
1515 |                     return true;
1516 |                 } else {
1517 |                     // If errors remain, update list and Prompt user
1518 |                     currentErrors = scanData.errors;
1519 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
1520 |                         // Recursively fix the *new* first error (since layout changed)
1521 |                         return await fixNext(0);
1522 |                     } else {
1523 |                         return false;
1524 |                     }
1525 |                 }
1526 | 
1527 |             } catch (e) {
1528 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
1529 |                     return await fixNext(index);
1530 |                 } else {
1531 |                     return false;
1532 |                 }
1533 |             }
1534 |         }
1535 | 
1536 |         return await fixNext(0);
1537 |     }
