3637 |     function formatBytes(bytes) {
3638 |         if (!bytes) return '0 B';
3639 |         const k = 1024;
3640 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3641 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3642 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3643 |     }
