3645 |     function timeAgo(dateString) {
3646 |         const date = new Date(dateString);
3647 |         const now = new Date();
3648 |         const seconds = Math.floor((now - date) / 1000);
3649 |         if (seconds < 10) return 'just now';
3650 |         if (seconds < 60) return seconds + 's ago';
3651 |         const minutes = Math.floor(seconds / 60);
3652 |         if (minutes < 60) return minutes + 'm ago';
3653 |         const hours = Math.floor(minutes / 60);
3654 |         if (hours < 24) return hours + 'h ago';
3655 |         return date.toLocaleDateString();
3656 |     }
