3773 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
3774 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
3775 |         
3776 |         const navItems = document.querySelectorAll('.nav-item');
3777 |         switchTab(tabId, navItems[navIndex]);
3778 | 
3779 |         const scrollContainer = document.querySelector('.main-view');
3780 |         let retryCount = 0;
3781 |         const MAX_RETRIES = 5;
3782 | 
3783 |         const attemptNavigation = async () => {
3784 |             const element = document.querySelector(selector);
3785 |             
3786 |             if (element) {
3787 |                 console.log("[DeepJump] Element found. Scrolling...");
3788 |                 
3789 |                 // Wait for any tab transition animations
3790 |                 await new Promise(r => setTimeout(r, 300));
3791 | 
3792 |                 let offsetTop = 0;
3793 |                 let curr = element;
3794 |                 while (curr && curr !== scrollContainer) {
3795 |                     offsetTop += curr.offsetTop;
3796 |                     curr = curr.offsetParent;
3797 |                 }
3798 | 
3799 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
3800 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
3801 | 
3802 |                 // Visual Highlight
3803 |                 element.style.transition = 'all 0.5s ease';
3804 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
3805 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
3806 |                 setTimeout(() => {
3807 |                     element.style.backgroundColor = '';
3808 |                     element.style.boxShadow = '';
3809 |                 }, 3000);
3810 |                 
3811 |                 console.groupEnd();
3812 |                 return true;
3813 |             }
3814 | 
3815 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
3816 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
3817 |                 retryCount++;
3818 |                 showGlobalToast("🔍 Searching deeper...");
3819 |                 
3820 |                 await loadMoreFn(); 
3821 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
3822 |                 return attemptNavigation();
3823 |             }
3824 | 
3825 |             console.error("[DeepJump] Failed: Element not found after retries.");
3826 |             showGlobalToast("Entry not found in recent history.", true);
3827 |             console.groupEnd();
3828 |             return false;
3829 |         };
3830 | 
3831 |         setTimeout(attemptNavigation, 100);
3832 |     }
