4670 | 
4671 |                 const batch = checked.slice(i, i + BATCH_SIZE);
4672 |                 statusEl.innerText = `⚡ Parallel Fetching: ${i + 1}-${Math.min(i + BATCH_SIZE, checked.length)} of ${checked.length}...`;
