1405 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1406 |     function applyLocalPatch(content, ops) {
1407 |         let lines = content.split('\n');
1408 |         let logs = [];
1409 |         let success = true;
1410 | 
1411 |         if (typeof ops === 'string') {
1412 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1413 |         }
1414 | 
1415 |         ops.forEach(op => {
1416 |             if (op.action === 'comment') return;
1417 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1418 |             
1419 |             if (op.action === 'replace_block') {
1420 |                 // Strategy 1: Exact String Match (Fastest)
1421 |                 const currentStr = lines.join('\n');
1422 |                 if (currentStr.includes(op.find_block)) {
1423 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1424 |                     logs.push('Exact match applied');
1425 |                     return;
1426 |                 }
1427 | 
1428 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1429 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1430 |                 if (searchLines.length === 0) return;
1431 | 
1432 |                 let matchStart = -1;
1433 |                 let matchEnd = -1;
1434 | 
1435 |                 // Scan file lines
1436 |                 for (let i = 0; i < lines.length; i++) {
1437 |                     // If first line matches (ignoring whitespace)
1438 |                     if (lines[i].trim() === searchLines[0]) {
1439 |                         // Check subsequent lines
1440 |                         let allMatch = true;
1441 |                         let fileOffset = 0;
1442 |                         let searchOffset = 1;
1443 |                         
1444 |                         while (searchOffset < searchLines.length) {
1445 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1446 |                             const nextFile = lines[i + fileOffset + 1].trim();
1447 |                             // Skip empty lines in file if they aren't in search block
1448 |                             if (nextFile === '') {
1449 |                                 fileOffset++;
1450 |                                 continue;
1451 |                             }
1452 |                             if (nextFile !== searchLines[searchOffset]) {
1453 |                                 allMatch = false;
1454 |                                 break;
1455 |                             }
1456 |                             fileOffset++;
1457 |                             searchOffset++;
1458 |                         }
1459 | 
1460 |                         if (allMatch) {
1461 |                             matchStart = i;
1462 |                             matchEnd = i + fileOffset;
1463 |                             break;
1464 |                         }
1465 |                     }
1466 |                 }
1467 | 
1468 |                 if (matchStart !== -1) {
1469 |                     // Replace the range of lines
1470 |                     const replacement = op.replace_with.split('\n');
1471 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1472 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1473 |                 } else {
1474 |                     success = false;
1475 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1476 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1477 |                 }
1478 |             }
1479 |         });
1480 |         return { content: lines.join('\n'), success, logs };
1481 |     }
