3652 |     function formatBytes(bytes) {
3653 |         if (!bytes) return '0 B';
3654 |         const k = 1024;
3655 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3656 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3657 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3658 |     }
