3660 |     function timeAgo(dateString) {
3661 |         const date = new Date(dateString);
3662 |         const now = new Date();
3663 |         const seconds = Math.floor((now - date) / 1000);
3664 |         if (seconds < 10) return 'just now';
3665 |         if (seconds < 60) return seconds + 's ago';
3666 |         const minutes = Math.floor(seconds / 60);
3667 |         if (minutes < 60) return minutes + 'm ago';
3668 |         const hours = Math.floor(minutes / 60);
3669 |         if (hours < 24) return hours + 'h ago';
3670 |         return date.toLocaleDateString();
3671 |     }
