3788 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
3789 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
3790 |         
3791 |         const navItems = document.querySelectorAll('.nav-item');
3792 |         switchTab(tabId, navItems[navIndex]);
3793 | 
3794 |         const scrollContainer = document.querySelector('.main-view');
3795 |         let retryCount = 0;
3796 |         const MAX_RETRIES = 5;
3797 | 
3798 |         const attemptNavigation = async () => {
3799 |             const element = document.querySelector(selector);
3800 |             
3801 |             if (element) {
3802 |                 console.log("[DeepJump] Element found. Scrolling...");
3803 |                 
3804 |                 // Wait for any tab transition animations
3805 |                 await new Promise(r => setTimeout(r, 300));
3806 | 
3807 |                 let offsetTop = 0;
3808 |                 let curr = element;
3809 |                 while (curr && curr !== scrollContainer) {
3810 |                     offsetTop += curr.offsetTop;
3811 |                     curr = curr.offsetParent;
3812 |                 }
3813 | 
3814 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
3815 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
3816 | 
3817 |                 // Visual Highlight
3818 |                 element.style.transition = 'all 0.5s ease';
3819 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
3820 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
3821 |                 setTimeout(() => {
3822 |                     element.style.backgroundColor = '';
3823 |                     element.style.boxShadow = '';
3824 |                 }, 3000);
3825 |                 
3826 |                 console.groupEnd();
3827 |                 return true;
3828 |             }
3829 | 
3830 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
3831 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
3832 |                 retryCount++;
3833 |                 showGlobalToast("🔍 Searching deeper...");
3834 |                 
3835 |                 await loadMoreFn(); 
3836 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
3837 |                 return attemptNavigation();
3838 |             }
3839 | 
3840 |             console.error("[DeepJump] Failed: Element not found after retries.");
3841 |             showGlobalToast("Entry not found in recent history.", true);
3842 |             console.groupEnd();
3843 |             return false;
3844 |         };
3845 | 
3846 |         setTimeout(attemptNavigation, 100);
3847 |     }
