4550 |     async function handleImportFileSelect(input) {
4551 |         const file = input.files[0];
4552 |         if (!file) return;
4553 |         
4554 |         const toast = document.createElement('div');
4555 |         toast.innerText = "Parsing " + file.name + "...";
4556 |         toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#333; color:white; padding:10px 20px; border-radius:30px; z-index:9999;";
4557 |         document.body.appendChild(toast);
4558 | 
4559 |         pendingImportFiles = [];
4560 | 
4561 |         try {
4562 |             if (file.name.endsWith('.zip')) {
4563 |                 const zip = await JSZip.loadAsync(file);
4564 |                 const promises = [];
4565 |                 zip.forEach((relativePath, zipEntry) => {
4566 |                     if (!zipEntry.dir) {
4567 |                         promises.push(zipEntry.async("string").then(content => {
4568 |                             pendingImportFiles.push({ path: relativePath, content: content });
4569 |                         }));
4570 |                     }
4571 |                 });
4572 |                 await Promise.all(promises);
4573 |             } 
4574 |             else if (file.name.endsWith('.txt')) {
4575 |                 const text = await file.text();
4576 |                 // Parse "FILE: path\nContent" format
4577 |                 // Split by "\n\nFILE: " to handle multiple files, assuming double newline separator from export
4578 |                 const chunks = text.split(/\n\nFILE: /g);
4579 |                 
4580 |                 chunks.forEach((chunk, index) => {
4581 |                     // Handle first chunk edge case if it starts with "FILE: "
4582 |                     let cleanChunk = chunk;
4583 |                     if (index === 0 && chunk.startsWith("FILE: ")) cleanChunk = chunk.substring(6);
4584 |                     
4585 |                     const firstLineEnd = cleanChunk.indexOf('\n');
4586 |                     if (firstLineEnd !== -1) {
4587 |                         const path = cleanChunk.substring(0, firstLineEnd).trim();
4588 |                         const content = cleanChunk.substring(firstLineEnd + 1);
4589 |                         if (path) pendingImportFiles.push({ path, content });
4590 |                     }
4591 |                 });
4592 |             } 
4593 |             else {
4594 |                 throw new Error("Unsupported file format. Use .zip or .txt exported from Conduit.");
4595 |             }
