function openFilterOverlay(tab) {
    currentFilterTab = tab;
    document.getElementById('filter-overlay').classList.add('active');
    document.getElementById('filter-title').innerText = `Filter ${tab.toUpperCase()}`;

    // Set active time pill
    document.querySelectorAll('.time-opt').forEach(btn => {
        btn.classList.toggle('active', btn.dataset.time === filters[tab].time);
    });

    // Extract files from context
    let dataset = [];
    if (tab === 'patcher') {
        // Scan visible logs in DOM since sessionLogs is transient
        document.querySelectorAll('#terminal-list .log-entry').forEach(el => {
            const response = JSON.parse(el.querySelector('textarea[id$="-response-data"]').value);
            if (response.results) dataset.push(...response.results.map(r => r.file));
        });
    } else if (tab === 'history') {
        dbHistory.forEach(h => { if(h.ops) h.ops.forEach(op => { if(op.file_path) dataset.push(op.file_path); })});
    } else if (tab === 'cicd') {
        cicdDataRaw.forEach(r => {
            const match = dbHistory.find(h => h.sha === r.head_commit.id);
            if (match && match.ops) match.ops.forEach(op => dataset.push(op.file_path));
        });
    }

    const uniqueFiles = [...new Set(dataset)].sort();
    const listContainer = document.getElementById('filter-file-list');

    if (uniqueFiles.length === 0) {
        listContainer.innerHTML = '<div style="padding:20px; text-align:center; color:#666;">No files detected in current results.</div>';
    } else {
        listContainer.innerHTML = uniqueFiles.map(f => `
            <label class="filter-checkbox-item">
                <input type="checkbox" class="filter-file-check" value="${f}" ${filters[tab].files.includes(f) || filters[tab].files.length === 0 ? 'checked' : ''}>
                <span>${f}</span>
            </label>
        `).join('');
    }
}

function setTimeFilter(val, btn) {
    filters[currentFilterTab].time = val;
    document.querySelectorAll('.time-opt').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
}

function toggleAllFilterFiles(checked) {
    document.querySelectorAll('.filter-file-check').forEach(cb => cb.checked = checked);
}

function applyActiveFilters() {
    const selectedFiles = Array.from(document.querySelectorAll('.filter-file-check:checked')).map(cb => cb.value);
    const allChecks = document.querySelectorAll('.filter-file-check');

    // If all are checked, we treat it as "No Filter"
    filters[currentFilterTab].files = (selectedFiles.length === allChecks.length) ? [] : selectedFiles;

    if (currentFilterTab === 'history') applyFiltersToHistory();
    else if (currentFilterTab === 'cicd') applyFiltersToCicd();
    else if (currentFilterTab === 'patcher') applyFiltersToPatcher();

    closeFilterOverlay();
}

function closeFilterOverlay() { document.getElementById('filter-overlay').classList.remove('active'); }

function filterDataset(items, tab) {
    const f = filters[tab];
    const now = Date.now();

    return items.filter(item => {
        // 1. Time Filter
        if (f.time !== 'all') {
            const ts = new Date(item.created_at).getTime();
            const diff = now - ts;
            if (f.time === 'hour' && diff > 3600000) return false;
            if (f.time === 'today' && diff > 86400000) return false;
            if (f.time === 'week' && diff > 604800000) return false;
        }

        // 2. File Filter
        if (f.files.length > 0) {
            let touchedFiles = [];
            if (tab === 'history') touchedFiles = (item.ops || []).map(o => o.file_path);
            if (tab === 'cicd') {
                const match = dbHistory.find(h => h.sha === item.head_commit.id);
                touchedFiles = match ? (match.ops || []).map(o => o.file_path) : [];
            }
            if (!touchedFiles.some(tf => f.files.includes(tf))) return false;
        }
        return true;
    });
}

function applyFiltersToHistory() {
    renderHistory(filterDataset(dbHistory, 'history'));
}

function applyFiltersToPatcher() {
    const f = filters.patcher;
    const now = Date.now();
    document.querySelectorAll('#terminal-list .log-entry').forEach(el => {
        // Skip runtime logs
        if (el.classList.contains('runtime-log')) return;

        const respData = el.querySelector('textarea[id$="-response-data"]')?.value;
        if (!respData) return;
        const resp = JSON.parse(respData);

        let visible = true;
        // Time Filter
        if (f.time !== 'all') {
            const ts = el.id.startsWith('term-saved-') ? new Date(resp.created_at).getTime() : parseInt(el.id.replace('term-', ''));
            const diff = now - ts;
            if (f.time === 'hour' && diff > 3600000) visible = false;
            else if (f.time === 'today' && diff > 86400000) visible = false;
        }
        // File Filter
        if (visible && f.files.length > 0) {
            const files = resp.results ? resp.results.map(r => r.file) : [];
            if (!files.some(path => f.files.includes(path))) visible = false;
        }
        el.style.display = visible ? 'block' : 'none';
    });
}

